-- =============================================================================
-- Historical DCR backfill — ENTRIES part 9 of 9  (554 days)
-- Run 01_catalog.sql first. Run parts in order. Idempotent (upsert). STAGING first.
-- =============================================================================
on conflict (entry_date, movie_id, screen_id) do update set
  shows=excluded.shows, share=excluded.share, cinema_id=excluded.cinema_id,
  updated_by='dcr-historical-import', updated_at=now();

on conflict (entry_date, movie_id, screen_id) do update set
  shows=excluded.shows, share=excluded.share, cinema_id=excluded.cinema_id,
  updated_by='dcr-historical-import', updated_at=now();
-- ===== VERIFICATION (read-only) =====
select count(*) entries, sum(jsonb_array_length(shows)) shows,
       min(entry_date) first_day, max(entry_date) last_day from public.entries;
select screen_id, count(*) entries from public.entries group by screen_id;
select jsonb_array_length(data->'movies') cfg_movies, jsonb_array_length(data->'classes') cfg_classes
from public.config where id=1;
select (select count(*) from public.movies) db_movies, (select count(*) from public.classes) db_classes;